import React, { useCallback, useEffect, useState } from 'react';
import { adminApi } from '../../services/api';

const COLOR_CLASSES = {
  blue:   { border: 'border-t-blue-500',   bar: 'bg-blue-500',   dot: 'bg-blue-500'   },
  orange: { border: 'border-t-orange-500', bar: 'bg-orange-500', dot: 'bg-orange-500' },
  purple: { border: 'border-t-purple-500', bar: 'bg-purple-500', dot: 'bg-purple-500' },
  red:    { border: 'border-t-red-500',    bar: 'bg-red-500',    dot: 'bg-red-500'    },
  green:  { border: 'border-t-green-500',  bar: 'bg-green-500',  dot: 'bg-green-500'  },
  cyan:   { border: 'border-t-cyan-500',   bar: 'bg-cyan-500',   dot: 'bg-cyan-500'   },
};

const BASE_DEPARTMENTS = [
  { name: 'Computer Science',       admin: 'Dr. Sarah Johnson',   capacity: 350, enrolled: 300, sla: 94, avgTime: '18h', color: 'blue'   },
  { name: 'Engineering',            admin: 'Prof. Michael Brown', capacity: 300, enrolled: 280, sla: 89, avgTime: '22h', color: 'orange' },
  { name: 'Business Administration', admin: 'Dr. Emily Davis',    capacity: 300, enrolled: 250, sla: 96, avgTime: '16h', color: 'purple' },
  { name: 'Medicine',               admin: 'Prof. James Wilson',  capacity: 200, enrolled: 180, sla: 88, avgTime: '24h', color: 'red'    },
  { name: 'Law',                    admin: 'Dr. Linda Martinez',  capacity: 150, enrolled: 142, sla: 92, avgTime: '20h', color: 'green'  },
  { name: 'Arts & Humanities',      admin: 'Prof. Robert Taylor', capacity: 200, enrolled: 178, sla: 91, avgTime: '19h', color: 'cyan'   },
];

const SuperAdminDepartments = () => {
  const [totalApplications, setTotalApplications] = useState(0);
  const [loading, setLoading] = useState(true);

  const load = useCallback(() => {
    setLoading(true);
    adminApi.getApplications()
      .then(({ data }) => setTotalApplications(data.length))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { load(); }, [load]);

  return (
    <div className="p-6 space-y-6">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Departments</h1>
          <p className="text-slate-500 mt-1">Manage university departments and monitor performance</p>
        </div>
        <button className="flex items-center gap-2 px-4 py-2.5 bg-red-600 hover:bg-red-700 text-white text-sm font-semibold rounded-lg transition shadow-sm">
          <svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
            <path d="M12 5v14M5 12h14"/>
          </svg>
          Add Department
        </button>
      </div>

      {/* Summary strip */}
      <div className="grid grid-cols-3 gap-4">
        {[
          { label: 'Total Departments', value: BASE_DEPARTMENTS.length, color: 'text-slate-900' },
          { label: 'Total Applications', value: loading ? '…' : totalApplications, color: 'text-red-600' },
          { label: 'Avg SLA Compliance', value: `${Math.round(BASE_DEPARTMENTS.reduce((s, d) => s + d.sla, 0) / BASE_DEPARTMENTS.length)}%`, color: 'text-green-600' },
        ].map(({ label, value, color }) => (
          <div key={label} className="bg-white rounded-xl border border-slate-200 p-5 shadow-sm text-center">
            <p className={`text-2xl font-bold ${color}`}>{value}</p>
            <p className="text-xs text-slate-500 mt-1 font-medium">{label}</p>
          </div>
        ))}
      </div>

      {/* Department cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {BASE_DEPARTMENTS.map((dept) => {
          const cc = COLOR_CLASSES[dept.color];
          const fillPct = Math.round((dept.enrolled / dept.capacity) * 100);
          const isBelowSla = dept.sla < 90;

          return (
            <div key={dept.name} className={`bg-white rounded-xl border border-slate-200 border-t-4 ${cc.border} shadow-sm hover:shadow-md transition-shadow`}>
              <div className="p-6">

                {/* Card header */}
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <h3 className="text-base font-bold text-slate-900">{dept.name}</h3>
                    <div className="flex items-center gap-1.5 mt-1 text-xs text-slate-500">
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                        <path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2M12 11a4 4 0 100-8 4 4 0 000 8z"/>
                      </svg>
                      <span>{dept.admin}</span>
                    </div>
                  </div>
                  <button className="p-1.5 rounded-lg hover:bg-slate-100 text-slate-400 transition">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                      <circle cx="12" cy="12" r="3"/><path d="M12 2v2M12 20v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M2 12h2M20 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/>
                    </svg>
                  </button>
                </div>

                {/* Metrics */}
                <div className="space-y-3">

                  {/* Enrollment bar */}
                  <div>
                    <div className="flex items-center justify-between mb-1 text-xs">
                      <span className="text-slate-500">Enrollment</span>
                      <span className="font-semibold text-slate-800">{dept.enrolled}/{dept.capacity}</span>
                    </div>
                    <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                      <div className={`h-full ${cc.bar} rounded-full transition-all`} style={{ width: `${fillPct}%` }}/>
                    </div>
                    <p className="text-right text-xs text-slate-400 mt-0.5">{fillPct}% capacity</p>
                  </div>

                  <div className="flex items-center justify-between text-sm">
                    <span className="text-slate-500 text-xs">SLA Compliance</span>
                    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold ${
                      isBelowSla ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'
                    }`}>
                      <span className={`w-1.5 h-1.5 rounded-full ${isBelowSla ? 'bg-amber-500' : 'bg-green-500'}`}/>
                      {dept.sla}%
                    </span>
                  </div>

                  <div className="flex items-center justify-between text-xs">
                    <span className="text-slate-500">Avg Review Time</span>
                    <span className="font-semibold text-slate-800">{dept.avgTime}</span>
                  </div>

                  <div className="flex items-center justify-between text-xs">
                    <span className="text-slate-500">Status</span>
                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold bg-green-100 text-green-700">
                      <span className="w-1.5 h-1.5 rounded-full bg-green-500"/>active
                    </span>
                  </div>
                </div>

                {/* Actions */}
                <div className="flex gap-2 mt-5">
                  <button className="flex-1 py-2 text-xs font-semibold text-slate-700 border border-slate-200 rounded-lg hover:bg-slate-50 transition">
                    View Details
                  </button>
                  <button className="flex-1 py-2 text-xs font-semibold text-slate-700 border border-slate-200 rounded-lg hover:bg-slate-50 transition">
                    Reports
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default SuperAdminDepartments;
